import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.data.elasticsearch.client.ClientConfiguration;
import org.springframework.data.elasticsearch.client.RestClients;
import org.springframework.data.elasticsearch.core.ElasticsearchOperations;
import org.springframework.data.elasticsearch.core.ElasticsearchRestTemplate;
import org.springframework.stereotype.Service;

import java.io.IOException;

@Service
public class ProductService {

    private final RestHighLevelClient client;

    @Autowired
    public ProductService(RestHighLevelClient client) {
        this.client = client;
    }

    public void indexProduct(Product product) throws IOException {
        IndexRequest request = new IndexRequest("products")
                .id(product.getId())
                .source(product.toJson(), XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    public SearchResponse searchProducts(String query, String category) throws IOException {
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        if (query != null && !query.isEmpty()) {
            sourceBuilder.query(QueryBuilders.matchQuery("description", query));
        }
        if (category != null && !category.isEmpty()) {
            sourceBuilder.aggregation(AggregationBuilders.terms("category_agg").field("category.keyword"));
        }

        SearchRequest searchRequest = new SearchRequest("products");
        searchRequest.source(sourceBuilder);
        return client.search(searchRequest, RequestOptions.DEFAULT);
    }
}

@Configuration
public class ElasticsearchConfig {

    @Bean
    public RestHighLevelClient client() {
        ClientConfiguration clientConfiguration = ClientConfiguration.builder()
                .connectedTo("localhost:9200")
                .build();
        return RestClients.create(clientConfiguration).rest();
    }

    @Bean
    public ElasticsearchOperations elasticsearchTemplate() {
        return new ElasticsearchRestTemplate(client());
    }
}

